template:
def matchPath(pattern: String, path: String): Boolean = {
  val patternSegs = pattern.split([[SLOT split_arg]]).toList
  val pathSegs = path.split([[SLOT split_arg]]).toList

  def matches(ps: List[String], ts: List[String]): Boolean = (ps, ts) match {
    case [[SLOT nil_case]] => true
    case (Nil, _) => false
    case ([[SLOT double_star]] :: pRest, _) =>
      // ** can match 0 or more segments
      // Try consuming 0, 1, 2, ... segments from target
      (0 to ts.length).exists { n =>
        matches(pRest, [[SLOT drop_call]])
      }
    case ([[SLOT single_star]] :: pRest, _ :: tRest) =>
      // * matches exactly one segment
      matches(pRest, tRest)
    case ("*" :: _, Nil) => false
    case (p :: pRest, t :: tRest) if p == t =>
      // Literal match
      matches(pRest, tRest)
    case _ => false
  }

  matches(patternSegs, pathSegs)
}
